    let encryptedBase64 = cipher.update(responseJson, 'utf8', 'base64');
    encryptedBase64 += cipher.final('base64');

    // ====================================================
    // 🔐 MAGIC SIGNATURE (Menggunakan Private Key Milikmu)
    // ====================================================
    console.log('[DEBUG] Signing response...');
    const sign = crypto.createSign('SHA256');
    sign.update(encryptedBase64); // Sign terhadap data yang sudah dienkripsi
    sign.end();
    
    // Ini akan menghasilkan Signature RSA murni yang SAH!
    const validSignatureBase64 = sign.sign(privateKey, 'base64'); 

    res.status(200).json({
      data: encryptedBase64,
      signature: validSignatureBase64 // BUKAN LAGI "111111"
    });

